    { id: 9, name: 'CSS Grid Layout Mastery', category: 'frontend' },
    { id: 10, name: 'Machine Learning with Python', category: 'data' },
];

function ResourceList() {
    const [searchInput, setSearchInput] = useState('');
    const [debouncedSearchTerm, setDebouncedSearchTerm] = useState('');

    // Debounce implementation (300ms) + immediate clear for empty/whitespace input.
    // Cleanup of timeout happens automatically via the effect return on re-runs and unmount.
    useEffect(() => {
        const trimmed = searchInput.trim();

        // Whitespace-only or empty input: treat as empty immediately (no debounce delay)
        if (trimmed === '') {
            setDebouncedSearchTerm('');
            return;
        }

        // Non-empty input: debounce the update
        const timeoutId = setTimeout(() => {
            setDebouncedSearchTerm(searchInput);
        }, 300);

        // Cleanup to prevent memory leaks and cancel stale updates
        return () => {
            clearTimeout(timeoutId);
        };
    }, [searchInput]);

    // Derive "searching" state: true while a non-empty input hasn't yet been committed
    // after the debounce delay. Clears instantly for empty input.
    const isSearching = searchInput.trim() !== '' && searchInput !== debouncedSearchTerm;

    // Filter using the debounced term only (case-insensitive substring on name)
    const filteredItems = useMemo(() => {
        const query = debouncedSearchTerm.trim().toLowerCase();
        if (!query) {
            return ITEMS;
        }
        return ITEMS.filter(item =>
            item.name.toLowerCase().includes(query)
        );
    }, [debouncedSearchTerm]);

