        const parts = text.split(regex);

        return parts
            .map((part, index) => {
                if (!part) return null;
                if (part.toLowerCase() === trimmedQuery.toLowerCase()) {
                    return <mark key={index}>{part}</mark>;
                }
                return part;
            })
            .filter(Boolean);
    };

    return (
        <div>
            <h2>Resources</h2>

            <input
                type="text"
                value={searchInput}
                onChange={(e) => setSearchInput(e.target.value)}
                placeholder="Search resources..."
                aria-label="Search resources"
